import { TextFieldProps } from ':components/TextField';
import { TestComponentProps } from 'src/types/test-component';

export type HelperPositionType = TextFieldProps['helperPosition'];

export interface PhoneInputProps extends TestComponentProps, Omit<React.HTMLAttributes<HTMLDivElement>, 'onChange'> {
	size?: 'small' | 'medium' | 'large';
	options?: Countries[];
	defaultCountry?: Countries;
	value?: string;
	onChange?: (event, value) => void;
	disabled?: boolean;
	error?: boolean;
	helperText?: string;
	label?: string;
	/**
	 * Позиционирование helper text.
	 */
	helperPosition?: HelperPositionType;
	/**
	 * Отключает отображение счетчика символов.
	 * Ограничение на ввод (maxLength) продолжает работать нативно.
	 */
	disableMaxLength?: boolean;
	/**
	 * Максимальное количество символов.
	 */
	maxLength?: number;
}

